const scoreMap = {
  "Há quanto tempo você trabalha com confeitaria?": {
    "Menos de 6 meses": 0,
    "De 6 meses a 1 ano": 1,
    "De 1 a 3 anos": 2,
    "Mais de 3 anos": 3,
  },

  "Qual a sua escolaridade?": {
    "Ensino médio incompleto": 0,
    "Ensino médico completo": 1,
    "Ensino médio completo": 1,
    "Ensino superior": 2,
  },

  "De onde vem sua principal fonte de renda?": {
    "Só Confeitaria": 3,
    "Confeitaria + Outro trabalho": 2,
    "Outro trabalho": 1,
  },

  "Qual sua média de faturamento hoje na confeitaria?": {
    "Sem faturamento": 0,
    "Menos de R$1.000": 0,
    "Entre R$1.000 E R$2.000": 1,
    "Entre R$2.000 E R$5.000": 2,
    "Mais de R$5.000": 3,
  },

  "Qual sua renda familiar total?": {
    "Até R$2.000": 0,
    "Entre R$2.000 E R$5.000": 1,
    "Acima de R$5.000": 2,
  },

  "Tem cartão de crédito?": {
    "Sim": 1,
    "Não": 0,
  },

  "Hoje, como você descreveria sua situação financeira?": {
    "Finanças organizadas.": 3,
    "Tenho dívidas, mas estão sob controle.": 2,
    "Tenho muitas dívidas, mas quero me organizar.": 1,
    "Minhas dívidas são uma grande dificuldade hoje, preciso de ajuda": 0,
  },

  "Ainda sobre a situação financeira do empreendedor, quando faz compras de maior valor, você costuma:": {
    "Parcelar no cartão": 2,
    "Pagar via Pix ou Boleto pois não tenho limite": 1,
    "Esperar juntar o dinheiro": 0,
  },

  "Qual a sua intimidade com redes sociais?": {
    "Tenho zero experiência, mas tenho interesse em aprender": 1,
    "Já conheço um pouco, mas tenho dificuldades": 2,
    "Já produzo conteúdo, mas me sinto perdida": 3,
    "Sou expert em redes sociais, mas ainda preciso de direcionamento": 4,
    "Já produzo bons conteudos em redes sociais, mas ainda preciso de direcionamento": 4,
  },

  "Já editou algum vídeo?": {
    "Nunca editei, e tenho muita dificuldade": 0,
    "Nunca editei, mas conheço alguns aplicativos": 1,
    "Já editei, mas não tenho muita prática": 2,
    "Edito com frequência, sou muito boa nisso": 3,
    "Edito com frequência, me saio bem": 3,
  },

  "Porque você está aqui?": {
    "Curiosidade": 1,
    "Sou confeiteira e quero renda extra ensinando": 2,
    "Estou decidida a ser professora de confeitaria": 4,
    "Já sou professora e quero escalar meus resultados": 3,
  },
};

return items.map(item => {
  const body = item.json.body || {};

  let leadScore = 0;
  const scoreDetails = {};

  for (const [question, answers] of Object.entries(scoreMap)) {
    const answer = body[question];
    const points = answers[answer] ?? 0;

    leadScore += points;

    scoreDetails[question] = {
      answer,
      points,
    };
  }

  return {
    json: {
      ...item.json,
      leadScore,
      scoreDetails,
    },
  };
});

